PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
ASK WHERE {
  wd:Q6362982 wdt:P1344 wd:Q19317
}

args.sparql:
SELECT (YEAR(?date) AS ?year) WHERE {
  VALUES ?competitionType { wd:Q11368 wd:Q11376 } .
  ?competition wdt:P31 ?competitionType ;
              wdt:P1344 wd:Q6362982 ;
              wdt:P580 ?date .
}
ORDER BY ASC(?date)
LIMIT 1
